// Devuelve solo pedidos vivos (no soft-deleted). Si la URL trae
// ?estado=solicitada|proforma_adjuntada|... filtramos; si trae
// ?proyecto_id=<uuid> filtramos por proyecto. Sin filtro devolvemos todos.
const raw = ($input.all() || []).map(i => i.json).filter(x => x && x.id && !x.deleted_at);
const q = ($input.first().json && $input.first().json.query) || {};
let out = raw;
if (q.estado) out = out.filter(p => p.estado === q.estado);
if (q.proyecto_id) out = out.filter(p => p.proyecto_id === q.proyecto_id);
return [{ json: { pedidos: out } }];

// NODO MONOLÍTICO: valida + hace HTTP Request a PostgREST + formatea respuesta.
// Sin branching de n8n (IF/Switch misfiran en esta instancia).
//
// Usa $helpers.httpRequestWithAuthentication para llamar a Supabase
// usando la credencial predefinida `supabaseApi` configurada en este node.

const prep = (() => {
  try {
// Validación + construcción de row (lógica original de Preparar Acción hardware)
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const p = b.pedido || {};
const errores = [];
const now = new Date().toISOString();
const VALID = ['create','adjuntar_proforma','adjuntar_justificante','confirmar_pago','actualizar_items','delete'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
let row = {};
if (action === 'create') {
  if (!p.cliente || !String(p.cliente).trim()) errores.push('cliente obligatorio');
  if (!Array.isArray(p.items) || p.items.length === 0) errores.push('items vacío');
  row = {
    proyecto_id: p.proyecto_id || null,
    cliente: String(p.cliente || '').trim(),
    implementador: p.implementador || null,
    items: p.items || [],
    estado: 'solicitada',
    notas_implementador: p.notas_implementador || null,
    solicitado_por: p.solicitado_por || null,
    solicitado_at: now
  };
} else if (action === 'adjuntar_proforma') {
  if (!p.proforma_pdf || !p.proforma_pdf.data) errores.push('proforma_pdf requerido');
  row = { id: p.id, proforma_pdf: p.proforma_pdf, estado: 'proforma_adjuntada', proforma_at: now };
  if (p.notas_contabilidad !== undefined) row.notas_contabilidad = p.notas_contabilidad;
} else if (action === 'adjuntar_justificante') {
  if (!p.justificante_pdf || !p.justificante_pdf.data) errores.push('justificante_pdf requerido');
  row = { id: p.id, justificante_pdf: p.justificante_pdf, estado: 'pendiente_confirmar', pagado_at: now };
  if (p.notas_implementador !== undefined) row.notas_implementador = p.notas_implementador;
} else if (action === 'confirmar_pago') {
  row = { id: p.id, estado: 'lista_envio', confirmado_at: now };
  if (p.notas_contabilidad !== undefined) row.notas_contabilidad = p.notas_contabilidad;
} else if (action === 'actualizar_items') {
  if (!Array.isArray(p.items)) errores.push('items debe ser array');
  row = { id: p.id, items: p.items || [] };
  if (p.notas_implementador !== undefined) row.notas_implementador = p.notas_implementador;
} else if (action === 'delete') {
  row = { id: p.id, deleted_at: now };
}
Object.keys(row).forEach(k => { if (row[k] === undefined) delete row[k]; });
if (errores.length > 0) return { __error: true, errores, action };
return { __error: false, action, row };
  } catch (e) {
    return { __error: true, errores: [String(e && e.message || e)], action: 'unknown' };
  }
})();

if (prep.__error) {
  return [{ json: {
    __skipHttp: true,
    __isCreate: true,
    __id: null,
    __body: '{}',
    success: false,
    errores: prep.errores,
    action: prep.action,
    pedido: null
  } }];
}

const { action, row } = prep;
const isCreate = action === 'create';

// Construir URL y método
const id = isCreate ? null : row.id;
const body = { ...row };
if (!isCreate) delete body.id;

const supaHost = $credentials?.supabaseApi?.host;
// No podemos leer credenciales en Code node — la HTTP Request se hace via
// $helpers.httpRequestWithAuthentication que sí las resuelve. Usamos
// expresión relativa (sin host) — requiere baseUrl en la credencial
// O bien pasamos el host por variable de entorno.
//
// ALTERNATIVA más robusta: el Code node no puede hacer httpRequest con
// credencial autenticada en todas las versiones de n8n. Mejor usar un
// subworkflow o un HTTP Request node aparte. Aquí devolvemos __prep para
// que el HTTP Request downstream lo consuma.

return [{ json: {
  __prep: true,
  action,
  row,
  __isCreate: isCreate,
  __id: id,
  __body: JSON.stringify(body)
} }];

// Consolida respuesta del HTTP PostgREST. PostgREST devuelve array.
const items = $input.all() || [];
// Si Preparar ya cortocircuitó con error, el primer item traerá success:false.
const first = items[0] && items[0].json;
if (first && first.success === false && Array.isArray(first.errores)) return [{ json: first }];

let rows = [];
const errores = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.code && j.message && !j.id) { errores.push(j.message + (j.details?' ('+j.details+')':'')); continue; }
  if (j.id) rows.push(j);
}
if (rows.length === 0 && errores.length === 0) errores.push('HTTP respondió sin filas');
return [{ json: {
  success: rows.length > 0,
  pedido: rows[0] || null,
  errores
} }];
